use parking_lot::RwLock;
use crate::distance::l2_distance;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

pub struct VectorDB {
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl Default for VectorDB {
    fn default() -> Self {
        Self::new()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write();
        data.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let len = vectors.len();
        let mut data = self.data.write();
        data.reserve(len);
        data.extend(vectors);
        len
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read();

        #[derive(PartialEq)]
        struct MinNonNan(f64);

        impl Eq for MinNonNan {}

        impl PartialOrd for MinNonNan {
            fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
                self.0.partial_cmp(&other.0)
            }
        }

        impl Ord for MinNonNan {
            fn cmp(&self, other: &Self) -> Ordering {
                self.partial_cmp(other).unwrap_or(Ordering::Equal)
            }
        }

        #[derive(Eq, PartialEq)]
        struct HeapElement {
            distance: MinNonNan,
            id: u64,
        }

        impl PartialOrd for HeapElement {
            fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
                Some(self.cmp(other))
            }
        }

        impl Ord for HeapElement {
            fn cmp(&self, other: &Self) -> Ordering {
                self.distance.cmp(&other.distance)
            }
        }

        let mut heap = BinaryHeap::with_capacity(top_k as usize + 1);

        for (id, v) in data.iter() {
            let dist = l2_distance(vector, v);

            if heap.len() < top_k as usize {
                heap.push(HeapElement {
                    distance: MinNonNan(dist),
                    id: *id,
                });
            } else if dist < heap.peek().unwrap().distance.0 {
                heap.pop();
                heap.push(HeapElement {
                    distance: MinNonNan(dist),
                    id: *id,
                });
            }
        }

        let mut results = heap.into_sorted_vec();
        results.into_iter().map(|e| SearchResult {
            id: e.id,
            distance: e.distance.0,
        }).collect()
    }
}
